// Demo dataset for the Door2Door artifact surface (/dashboard/d2d).
//
// MOCK data for the demo. Types mirror the real `d2d_visits` / `d2d_workers`
// schema (see core/src/app/api/agent/d2d/log/route.ts) so a later swap to a live
// GET route is mechanical. ~186 visits: ~30 hand-curated (rich grievance notes)
// + the rest generated by a SEEDED PRNG so the set is deterministic (no SSR/
// hydration drift) yet realistic for KPIs, pagination, donut and top-issues.
// Field photos are real local thumbnails in /public/d2d-photos.

// ── value unions (match the DB / API) ───────────────────────────────────────
export type D2DOutcome = 'met' | 'not_home' | 'refused' | 'revisit';
export type D2DLean = 'supporter' | 'leaning' | 'undecided' | 'opposed';
export type GrievanceKey =
  | 'jobs' | 'water' | 'power' | 'roads' | 'drugs'
  | 'farm_debt' | 'health' | 'education' | 'other';
export type LoopStatus = 'raised' | 'routed' | 'resolved';

// ── shapes ───────────────────────────────────────────────────────────────────
export interface HouseholdMember {
  name: string;
  age: number;
  gender: 'M' | 'F';
  relation: string;
  voterIdMatched: boolean; // EPIC (voter-ID) matched on the doorstep
}

export interface D2DPhoto {
  id: string;
  url: string;   // real thumbnail in /public/d2d-photos
  label: string; // "House front", "Water supply", …
  takenAt: string;
}

export interface D2DSurvey {
  householdSize: number;
  members: HouseholdMember[];
  membersSpokenTo: number;
  flagHung: boolean;
  grievanceCategory?: GrievanceKey;
  grievanceNote?: string;
  lean?: D2DLean;
}

export interface VisitTimelineEntry {
  at: string;
  label: string;
  outcome: D2DOutcome;
}

export interface D2DVisit {
  id: string;
  householdHead: string;
  phone: string | null;
  workerId: string;
  workerName: string;
  workerPhone: string;
  constituency: string;
  district: string;
  acNo: number;
  boothNo: number;
  boothName: string;
  addressNote: string;
  latitude: number | null;
  longitude: number | null;
  outcome: D2DOutcome;
  notes?: string;
  survey: D2DSurvey | null;
  surveyVersion: string | null;
  photos: D2DPhoto[];
  loopStatus?: LoopStatus;
  visitedAt: string;
  timeline: VisitTimelineEntry[];
}

export interface D2DWorker {
  id: string;
  name: string;
  phone: string;
  constituency: string;
  district: string;
  boothAssignments: string[];
  verificationCode: string;
  status: 'active' | 'inactive';
}

export interface BoothCampaign {
  id: string;
  name: string;
  description: string;
  constituency: string;
  district: string;
  booths: number[];
  startDate: string;
  endDate: string;
  targetDoors: number;
  doorsDone: number;
  workerIds: string[];
  status: 'active' | 'completed';
}

