// ── time helpers (generated relative to now) ─────────────────────────────────
const NOW = Date.now();
export function hoursAgo(h: number): string {
  return new Date(NOW - h * 3_600_000).toISOString();
}
export function daysAgo(d: number): string {
  return hoursAgo(d * 24);
}
export function timeAgo(iso: string | null | undefined): string {
  if (!iso) return '-';
  const diffMs = NOW - new Date(iso).getTime();
  const mins = Math.floor(diffMs / 60000);
  if (mins < 1) return 'now';
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  const days = Math.floor(hrs / 24);
  if (days < 30) return `${days}d ago`;
  return `${Math.floor(days / 30)}mo ago`;
}
export function districtColor(d: string): string {
  let h = 0;
  for (let i = 0; i < d.length; i++) h = (h * 31 + d.charCodeAt(i)) % 360;
  return `hsl(${h}, 60%, 52%)`;
}

