const PB = '/d2d-photos/';
const HOUSE_PICS = ['house-a', 'house-b', 'house-c', 'house-d'];
const GRV_PICS: Record<GrievanceKey, string[]> = {
  water: ['water-a', 'water-b'],
  power: ['power-a'],
  roads: ['road-a'],
  farm_debt: ['farm-a', 'farm-b'],
  education: ['school-a'],
  drugs: ['lane-a'],
  health: ['drain-a'],
  jobs: ['lane-a'],
  other: ['drain-a'],
};
function picLabel(slug: string): string {
  if (slug.startsWith('house')) return 'House front';
  if (slug.startsWith('water')) return 'Water supply';
  if (slug.startsWith('power')) return 'Power lines';
  if (slug.startsWith('road')) return 'Road condition';
  if (slug.startsWith('drain')) return 'Drainage';
  if (slug.startsWith('school')) return 'School';
  if (slug.startsWith('farm')) return 'Farm land';
  if (slug.startsWith('lane')) return 'Street';
  return 'Photo';
}
function photo(slug: string, id: string, at: string): D2DPhoto {
  return { id, url: `${PB}${slug}.jpg`, label: picLabel(slug), takenAt: at };
}

