// ── curated visit factory ────────────────────────────────────────────────────
let _seq = 0;
interface VisitSpec {
  head: string; phone?: string | null; workerId: string; boothNo: number; addr: string;
  outcome: D2DOutcome; hoursAgo: number; members?: HouseholdMember[]; spokenTo?: number;
  flagHung?: boolean; grievance?: GrievanceKey; grievanceNote?: string; lean?: D2DLean;
  loop?: LoopStatus; notes?: string; extraHousePic?: boolean;
  priorKnock?: { outcome: D2DOutcome; hoursAgo: number; label?: string };
}
function m(name: string, age: number, gender: 'M' | 'F', relation: string, voterIdMatched = true): HouseholdMember {
  return { name, age, gender, relation, voterIdMatched };
}
function buildPhotos(spec: { grievance?: GrievanceKey; extraHousePic?: boolean }, seqIx: number, at: string): D2DPhoto[] {
  const out: D2DPhoto[] = [];
  out.push(photo(HOUSE_PICS[seqIx % HOUSE_PICS.length], `p${seqIx}-h`, at));
  if (spec.grievance) {
    const pool = GRV_PICS[spec.grievance];
    out.push(photo(pool[seqIx % pool.length], `p${seqIx}-g`, at));
  }
  if (spec.extraHousePic) out.push(photo(HOUSE_PICS[(seqIx + 2) % HOUSE_PICS.length], `p${seqIx}-h2`, at));
  return out;
}
function mkVisit(s: VisitSpec): D2DVisit {
  _seq += 1;
  const b = BOOTHS[s.boothNo];
  const w = workerById[s.workerId];
  const visitedAt = hoursAgo(s.hoursAgo);
  const isMet = s.outcome === 'met';
  const survey: D2DSurvey | null = isMet && s.members
    ? {
        householdSize: s.members.length,
        members: s.members,
        membersSpokenTo: s.spokenTo ?? Math.min(s.members.length, 2),
        flagHung: !!s.flagHung,
        grievanceCategory: s.grievance,
        grievanceNote: s.grievanceNote,
        lean: s.lean,
      }
    : null;
  const photos = isMet ? buildPhotos(s, _seq, visitedAt) : [];
  const timeline: VisitTimelineEntry[] = [];
  if (s.priorKnock) {
    timeline.push({
      at: hoursAgo(s.priorKnock.hoursAgo),
      label: s.priorKnock.label || (s.priorKnock.outcome === 'not_home' ? 'First knock - not home' : `First knock - ${D2D_OUTCOME[s.priorKnock.outcome].label.toLowerCase()}`),
      outcome: s.priorKnock.outcome,
    });
  }
  timeline.push({
    at: visitedAt,
    label: s.outcome === 'met' ? `${s.priorKnock ? 'Revisit - met' : 'Met'}${s.flagHung ? ', flag hung' : ''}` : D2D_OUTCOME[s.outcome].label,
    outcome: s.outcome,
  });
  return {
    id: `v${_seq}`,
    householdHead: s.head,
    phone: s.phone === undefined ? (isMet ? `+9198${String(76000000 + _seq * 7).slice(0, 8)}` : null) : s.phone,
    workerId: s.workerId, workerName: w.name, workerPhone: w.phone,
    constituency: b.constituency, district: b.district, acNo: b.acNo,
    boothNo: b.no, boothName: b.name, addressNote: s.addr,
    latitude: b.lat, longitude: b.lng,
    outcome: s.outcome, notes: s.notes,
    survey, surveyVersion: isMet ? 'v1' : null, photos,
    loopStatus: s.grievance ? s.loop || 'raised' : undefined,
    visitedAt, timeline,
  };
}

