// ── seeded generator (fills out to ~186) ─────────────────────────────────────
function mulberry32(seed: number) {
  return function () {
    seed |= 0; seed = (seed + 0x6D2B79F5) | 0;
    let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
const rnd = mulberry32(0x50504f50); // fixed seed → deterministic
const pick = <T,>(arr: T[]): T => arr[Math.floor(rnd() * arr.length)];
const weighted = <T,>(items: [T, number][]): T => {
  const total = items.reduce((s, [, w]) => s + w, 0);
  let r = rnd() * total;
  for (const [v, w] of items) { if ((r -= w) <= 0) return v; }
  return items[items.length - 1][0];
};

const MALE = ['Harjit', 'Gurmeet', 'Balwinder', 'Jarnail', 'Ranjit', 'Davinder', 'Surinder', 'Tejinder', 'Kuldeep', 'Amarjit', 'Hardeep', 'Sukhwinder', 'Jagtar', 'Balkar', 'Nirmal', 'Pargat', 'Malkit', 'Charanjit', 'Rachhpal', 'Beant', 'Avtar', 'Harbans', 'Gurmail', 'Sohan', 'Mohinder'];
const FEMALE = ['Harpreet', 'Rajwinder', 'Baljit', 'Kuldeep', 'Manjit', 'Surjit', 'Amandeep', 'Gurmeet', 'Paramjit', 'Sarbjit', 'Jasbir', 'Narinder', 'Charanjit', 'Balwinder', 'Harjinder', 'Ravinder', 'Sukhjit', 'Daljit'];
const SURNAME = ['Singh', 'Singh', 'Singh', 'Kaur', 'Kaur', 'Sharma', 'Kumar', 'Garg', 'Lal', 'Rani'];
const RELATION_M = ['Son', 'Father', 'Brother', 'Uncle'];
const RELATION_F = ['Daughter', 'Mother', 'Spouse', 'Daughter-in-law'];

function genMembers(): HouseholdMember[] {
  const size = weighted<number>([[2, 3], [3, 4], [4, 5], [5, 3], [6, 2]]);
  const headMale = rnd() > 0.25;
  const headSur = pick(SURNAME.filter((s) => s !== 'Kaur' && s !== 'Rani')) || 'Singh';
  const members: HouseholdMember[] = [];
  const head = headMale ? `${pick(MALE)} ${headSur === 'Kaur' ? 'Singh' : headSur}` : `${pick(FEMALE)} Kaur`;
  members.push(m(head, 38 + Math.floor(rnd() * 30), headMale ? 'M' : 'F', 'Head', true));
  if (size > 1) members.push(m(`${pick(FEMALE)} Kaur`, 34 + Math.floor(rnd() * 26), 'F', 'Spouse', rnd() > 0.15));
  for (let i = members.length; i < size; i++) {
    const male = rnd() > 0.5;
    const age = 8 + Math.floor(rnd() * 45);
    members.push(m(
      male ? `${pick(MALE)} Singh` : `${pick(FEMALE)} Kaur`,
      age, male ? 'M' : 'F',
      male ? pick(RELATION_M) : pick(RELATION_F),
      age >= 18 ? rnd() > 0.35 : false,
    ));
  }
  return members;
}

function generated(count: number): D2DVisit[] {
  const out: D2DVisit[] = [];
  for (let i = 0; i < count; i++) {
    const boothNo = pick(BOOTH_NOS);
    const w = pick(workersForBooth(boothNo).length ? workersForBooth(boothNo) : WORKERS);
    const outcome = weighted<D2DOutcome>([['met', 0.68], ['not_home', 0.15], ['revisit', 0.11], ['refused', 0.06]]);
    const hrs = 4 + rnd() * 164; // spread over ~7 days, after the curated recent ones
    if (outcome !== 'met') {
      const spec: VisitSpec = {
        head: rnd() > 0.3 ? `${pick(MALE)} Singh` : `${pick(FEMALE)} Kaur`,
        workerId: w.id, boothNo, addr: `H.No ${20 + Math.floor(rnd() * 260)}, ${pick(['Gali No 3', 'Gali No 5', 'Gali No 8', 'Main Bazaar', 'Ward 4', 'Ward 7', 'Model Colony'])}`,
        outcome, hoursAgo: hrs,
        notes: outcome === 'refused' ? pick(['Not interested', 'Busy, declined', 'Asked not to return']) : undefined,
        priorKnock: outcome === 'revisit' ? { outcome: 'not_home', hoursAgo: hrs + 48 + rnd() * 72 } : undefined,
      };
      out.push(mkVisit(spec));
      continue;
    }
    const members = genMembers();
    const lean = weighted<D2DLean>([['supporter', 0.40], ['leaning', 0.32], ['undecided', 0.18], ['opposed', 0.10]]);
    const hasGrievance = rnd() > 0.4;
    const grievance = hasGrievance
      ? weighted<GrievanceKey>([['water', 0.2], ['power', 0.16], ['roads', 0.13], ['jobs', 0.12], ['health', 0.1], ['farm_debt', 0.1], ['drugs', 0.07], ['education', 0.07], ['other', 0.05]])
      : undefined;
    const spec: VisitSpec = {
      head: members[0].name, workerId: w.id, boothNo,
      addr: `H.No ${20 + Math.floor(rnd() * 260)}, ${pick(['Gali No 3', 'Gali No 5', 'Gali No 8', 'Main Bazaar', 'Ward 4', 'Ward 7', 'Model Colony'])}`,
      outcome: 'met', hoursAgo: hrs, members, spokenTo: 1 + Math.floor(rnd() * Math.min(3, members.length)),
      flagHung: rnd() > 0.6, grievance,
      grievanceNote: grievance ? GRV_NOTE[grievance][Math.floor(rnd() * GRV_NOTE[grievance].length)] : undefined,
      lean, loop: grievance ? weighted<LoopStatus>([['raised', 0.5], ['routed', 0.35], ['resolved', 0.15]]) : undefined,
      extraHousePic: rnd() > 0.7,
    };
    const v = mkVisit(spec);
    // only ~55% of met visits carry photos → keeps total near the mockup's count
    if (rnd() > 0.55) v.photos = [];
    out.push(v);
  }
  return out;
}

