// Table shows a short RECENT sample (≤5 pages). The hero aggregates below are
// separate, at real campaign scale (a week of D2D reaches tens of thousands).
export const VISITS: D2DVisit[] = [...CURATED, ...generated(240)];

// ── campaign-scale aggregates (headline KPIs / donut / issues) ───────────────
// Magnitudes are fixed to a realistic week; PROPORTIONS (outcome mix, issue mix,
// lean split) are derived from the sample so everything stays internally
// consistent. Formatting is manual (deterministic) to avoid locale hydration drift.
export function fmt(n: number): string {
  return Math.round(n).toString().replace(/\B(?=(\d{3})+(?!\d))/g, ',');
}
export interface CampaignStats {
  households: number; planned: number; members: number; photos: number;
  grievances: number; followUp: number; supportPct: number;
  leanCounts: Record<D2DLean, number>; leanTotal: number;
  outcomeSplit: { outcome: D2DOutcome; count: number; pct: number }[];
  topIssues: { cat: GrievanceKey; count: number }[];
}
function computeCampaignStats(): CampaignStats {
  const met = VISITS.filter((v) => v.outcome === 'met');
  const total = VISITS.length || 1;
  const outcomeCounts: Record<D2DOutcome, number> = { met: 0, not_home: 0, refused: 0, revisit: 0 };
  VISITS.forEach((v) => { outcomeCounts[v.outcome] += 1; });
  const grv: Record<string, number> = {};
  met.forEach((v) => { const g = v.survey?.grievanceCategory; if (g) grv[g] = (grv[g] || 0) + 1; });
  const leanCounts: Record<D2DLean, number> = { supporter: 0, leaning: 0, undecided: 0, opposed: 0 };
  met.forEach((v) => { if (v.survey?.lean) leanCounts[v.survey.lean] += 1; });
  const leanTotal = leanCounts.supporter + leanCounts.leaning + leanCounts.undecided + leanCounts.opposed;
  const supportPct = leanTotal ? Math.round(((leanCounts.supporter + leanCounts.leaning) / leanTotal) * 100) : 0;

  // fixed weekly magnitudes
  const households = 47_200, planned = 78_000, members = 138_400, photos = 22_600, grievances = 9_480, followUp = 6_840;

  const order: D2DOutcome[] = ['met', 'not_home', 'refused', 'revisit'];
  const outcomeSplit = order.map((o) => {
    const p = outcomeCounts[o] / total;
    return { outcome: o, count: Math.round(households * p), pct: Math.round(p * 100) };
  });
  outcomeSplit[0].count += households - outcomeSplit.reduce((s, x) => s + x.count, 0); // absorb rounding

  const grvSample = Object.values(grv).reduce((a, b) => a + b, 0) || 1;
  const topIssues = Object.entries(grv).sort((a, b) => b[1] - a[1]).slice(0, 5)
    .map(([k, n]) => ({ cat: k as GrievanceKey, count: Math.round(grievances * (n / grvSample)) }));

  return { households, planned, members, photos, grievances, followUp, supportPct, leanCounts, leanTotal, outcomeSplit, topIssues };
}
export const CAMPAIGN_STATS = computeCampaignStats();

